import { Button, ModalR, RenderTitle, Spinner, MultiselectWithSearchR } from '../../../common';
import { useCallback, useEffect, useState } from 'react';
import cls from './WorkflowTemplatesModal.module.scss';
import Select from 'react-select';
import { workflow_templates } from '../../../../shared/utility';
import { connect } from 'react-redux';
import { createNewProcess, createProcessTemplate, getProcessById, shareProcessToSeveralPositions, updatingProcessById } from '../../../../services/processes.service';
import { setMessageBar, setSelectedProcess, setShowMenu, setShowSideMenu } from '../../../../reduxStore/actions/flowActions';
import { store } from '../../../../reduxStore/store';
import { isMobile, isSafari } from 'react-device-detect';

import MessageContainer from '../../ProcessesComps/MessageContainer/MessageContainer';
import { first, tap } from 'rxjs';
import { useNavigate } from 'react-router-dom';
import Loader from 'react-loader-spinner';


const WorkflowTemplatesModal = props => {
	const { isOpen, shadowedContainerStyle, onCreateBlank, gotoProcess } = props;
	const [error, setError] = useState('');
	const [loading, setLoading] = useState(false);


	const navigate = useNavigate();
	const renderWorkflows = () => {
		return workflow_templates?.map((template, index) => (
			<div className={cls.currentInvoicesContainer} style={{ maxWidth: '40%' }} key={index}>
				<p className={cls.trialTitle}>{`Templates`}</p>
				<hr style={{ borderTop: '1px solid #D2D2D2', marginBottom: '20px' }} />
				<div className={cls.header} >
					<p className={cls.trialText}>{`${template.name}`}</p>
					<Button
						title={`Use`}
						style={{ backgroundColor: 'rgb(83, 159, 234)', width: '140px' }}
						clicked={() => {
							setLoading(true);
							createProcessTemplate(template.data).pipe(first()).subscribe({
								next: data => {
									console.log('data', data)
									setLoading(false);

									store.dispatch(setSelectedProcess({
										name: data?.name,
										description: data?.description,
										id: data.id,
										is_pinned: data?.is_pinned,
										user_id: data?.user_id,
										registered: true,
										type: data?.type,
										steps: data?.steps,
									}));
									gotoProcess(data);


								},
								error: error => {
									console.log('error', error)
									setLoading(false);
								}
							})
						}}
					/>
				</div>
				<p className={cls.trialTitle} style={{ fontSize: '18px', color: 'black', fontWeight: '400' }}>{`${template.category} :  ${template.subcategory}`}</p>
				<p className={cls.subTitle}>{`${template.description}`}</p>
			</div>
		));
	};

	const blankWorkflow = () => {
		return <div className={cls.currentInvoicesContainer} style={{ maxWidth: '40%' }} >
			<p className={cls.trialTitle}>{`New`}</p>
			<hr style={{ borderTop: '1px solid #D2D2D2', marginBottom: '20px' }} />
			<div className={cls.header}>
				<p className={cls.trialText}>{`Blank Workflow`}</p>
				<Button
					title={`Create`}
					style={{ width: '140px' }}
					clicked={onCreateBlank}
				/>
			</div>
			<br/>
			<br/>
			<p className={cls.subTitle}>{`Create your workflow using a blank canvass`}</p>
		</div>
			;
	};

	return (
		<ModalR isOpen={isOpen} blured={true} scrollable={true} shadowedContainerStyle={shadowedContainerStyle}>
			<div className={cls.host}>
				<p className={cls.title} >
					{'New Workflow'}
				</p>
				<p className={cls.subtitle} >
					{'Start a new workflow or select from any of our predefined templates'}
				</p>
				{loading ? (
					<Loader type={isSafari ? 'Watch' : 'Puff'} color={'var(--app-color-gray-dark)'} secondaryColor="gray" radius={24} height={24} width={`24px`} />
				) : null}
				{blankWorkflow()}
				{renderWorkflows()}
			</div>
			<div className={cls.controls}>
				<Button loading={loading} title={'Close'} clicked={() => navigate('/')} />


			</div>

		</ModalR>
	);
};

const mapStateToProps = store => {
	const { companyProcesses, companyPositionsArray, allModules, components, onBoardingCompleted } = store.flowReducer;
	return { companyProcesses, companyPositionsArray, allModules, components, onBoardingCompleted };
};

export default connect(mapStateToProps)(WorkflowTemplatesModal);
